# тФАтФА text style тФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФА
async def style_handler(u:Update,ctx:ContextTypes.DEFAULT_TYPE):
    t=u.message.text
    rows=[[IKB(fn(t),copy_text=CopyTextButton(fn(t)))] for lbl,fn in TS]
    rows.append([IKB("тЬНя╕П сЮКсЯЖсЮОсЮ╛сЮЪсЮАсЮ╢сЮЪсЮРсЯТсЮШсЮ╕",callback_data="style_new"),IKB("ЁЯПа сЮШсЯЙсЮ║сЮУсЮ╗сЮЩсЮШсЯБ",callback_data="home")])
    kb=IKM(rows); txt=f"тЬНя╕П <b>Style:</b> <code>{t}</code>\nЁЯСЗ сЮЕсЮ╗сЮЕ button сЮКсЮ╛сЮШсЯТсЮФсЮ╕ <b>Copy</b>"
    cid=u.message.chat_id; mid=ctx.user_data.get("mid")
    try: await u.message.delete()
    except: pass
    if mid:
        try:
            await ctx.bot.edit_message_text(chat_id=cid,message_id=mid,text=txt,reply_markup=kb,parse_mode=H)
            return S_STYLE
        except: pass
    msg=await ctx.bot.send_message(chat_id=cid,text=txt,reply_markup=kb,parse_mode=H)
    _save(ctx,msg); return S_STYLE

# тФАтФА image тЖТ PDF тФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФА
async def pdf_photo(u:Update,ctx:ContextTypes.DEFAULT_TYPE):
    p=u.message.photo[-1] if u.message.photo else None
    dc=u.message.document if u.message.document else None
    if not p and not dc:
        cid=u.message.chat_id; await _edit_or_send(ctx,cid,"тЪая╕П Upload сЮЪсЮ╝сЮФсЮЧсЮ╢сЮЦ!",IK_CANCEL_DOC); return S_PDF
    f=await ctx.bot.get_file(p.file_id if p else dc.file_id)
    ctx.user_data.setdefault("pdf_photos",[]).append(bytes(await f.download_as_bytearray()))
    n=len(ctx.user_data["pdf_photos"]); cid=u.message.chat_id
    txt=f"ЁЯЦ╝я╕П <b>сЮФсЮ╢сЮУсЮСсЮСсЮ╜сЮЫ {n} сЮЪсЮ╝сЮФ</b>\nUpload сЮФсЮУсЯТсЮРсЯВсЮШ сЮм сЮЕсЮ╗сЮЕ <b>сЮФсЮДсЯТсЮАсЮ╛сЮП PDF</b>"
    mid=ctx.user_data.get("mid")
    if mid and n>1:
        try:
            await ctx.bot.edit_message_text(chat_id=cid,message_id=mid,text=txt,reply_markup=ik_pdf(n),parse_mode=H)
            return S_PDF
        except: pass
    msg=await u.message.reply_text(txt,reply_markup=ik_pdf(n),parse_mode=H)
    _save(ctx,msg); return S_PDF

async def _pdf_build(q,ctx:ContextTypes.DEFAULT_TYPE):
    photos=ctx.user_data.get("pdf_photos",[])
    if not photos:
        await q.edit_message_text("тЪая╕П сЮШсЮ╖сЮУсЮСсЮ╢сЮУсЯЛсЮШсЮ╢сЮУсЮЪсЮ╝сЮФсЮЧсЮ╢сЮЦ!",reply_markup=IK_CANCEL_DOC,parse_mode=H); return S_PDF
    await q.edit_message_text(f"тП│ <b>сЮАсЯЖсЮЦсЮ╗сЮДсЮФсЯЖсЮФсЯТсЮЫсЯВсЮД {len(photos)} сЮЪсЮ╝сЮФ тЖТ PDF...</b>",parse_mode=H)
    pdf=FPDF()
    for raw in photos:
        img=Image.open(io.BytesIO(raw)).convert("RGB"); w,h=img.size
        pw,ph=w*25.4/96,h*25.4/96
        pdf.add_page(format=(pw,ph)); pdf.set_margins(0,0,0); pdf.set_auto_page_break(False)
        tmp=io.BytesIO(); img.save(tmp,format="JPEG",quality=95); tmp.seek(0)
        pdf.image(tmp,x=0,y=0,w=pw,h=ph)
    buf=io.BytesIO(bytes(pdf.output()))
    await ctx.bot.send_document(chat_id=q.message.chat_id,document=InputFile(buf,filename="KhmerBot.pdf"),
        caption=f"тЬЕ <b>PDF сЮФсЮДсЯТсЮАсЮ╛сЮПсЮЗсЯДсЮВсЮЗсЯРсЮЩ!</b>\nЁЯЦ╝я╕П {len(photos)} сЮСсЯЖсЮЦсЯРсЮЪ",parse_mode=H)
    msg=await ctx.bot.send_message(chat_id=q.message.chat_id,text="ЁЯСЗ <b>сЮЗсЯТсЮЪсЮ╛сЮЯсЮЪсЮ╛сЮЯ:</b>",reply_markup=IK_MAIN,parse_mode=H)
    ctx.user_data["pdf_photos"]=[]; _save(ctx,msg); return S_MAIN

# тФАтФА PDF тЖТ image тФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФА
async def pdf2img(u:Update,ctx:ContextTypes.DEFAULT_TYPE):
    dc=u.message.document; fmt=ctx.user_data.get("pdf2img_fmt","PNG"); cid=u.message.chat_id
    if not dc or not (dc.mime_type=="application/pdf" or (dc.file_name or "").lower().endswith(".pdf")):
        await _edit_or_send(ctx,cid,"тЪая╕П Upload сЮпсЮАсЮЯсЮ╢сЮЪ <b>PDF</b>!",IK_CANCEL_DOC); return S_PDF2IMG
    try:
        await _edit_or_send(ctx,cid,f"тП│ <b>сЮАсЯЖсЮЦсЮ╗сЮДсЮФсЯЖсЮФсЯТсЮЫсЯВсЮД PDF тЖТ {fmt}...</b>")
        raw=bytes(await (await ctx.bot.get_file(dc.file_id)).download_as_bytearray())
        doc=fitz.open(stream=raw,filetype="pdf"); total=len(doc)
        ext=fmt.lower(); pil_fmt="PNG" if fmt=="PNG" else "JPEG"; media=[]
        for i,page in enumerate(doc):
            pix=page.get_pixmap(matrix=fitz.Matrix(150/72,150/72),alpha=False)
            img=Image.frombytes("RGB",[pix.width,pix.height],pix.samples)
            buf=io.BytesIO(); img.save(buf,format=pil_fmt,quality=90 if fmt=="JPG" else None); buf.seek(0)
            media.append((buf,f"page_{i+1:02d}.{ext}"))
        doc.close()
        for idx,(buf,name) in enumerate(media):
            last=idx==len(media)-1
            cap=f"тЬЕ <b>{'сЮФсЯЖсЮФсЯТсЮЫсЯВсЮДсЮЗсЯДсЮВсЮЗсЯРсЮЩ! 1 сЮСсЯЖсЮЦсЯРсЮЪ' if total==1 else f'сЮСсЯЖсЮЦсЯРсЮЪ {idx+1}/{total}' if not last else f'сЮЪсЮ╜сЮЕсЮЪсЮ╢сЮЫсЯЛ! {total} сЮСсЯЖсЮЦсЯРсЮЪ тЖТ {fmt}'}</b>"
            await u.message.reply_document(document=InputFile(buf,filename=name),caption=cap,parse_mode=H)
        msg=await u.message.reply_text("ЁЯСЗ <b>сЮЗсЯТсЮЪсЮ╛сЮЯсЮЪсЮ╛сЮЯ:</b>",reply_markup=IK_MAIN,parse_mode=H)
        _save(ctx,msg)
    except Exception as e:
        logger.error(f"pdf2img: {e}")
        await _edit_or_send(ctx,cid,"тЭМ <b>сЮШсЮ╢сЮУсЮФсЮЙсЯТсЮасЮ╢! сЮЦсЯТсЮЩсЮ╢сЮЩсЮ╢сЮШсЮШсЯТсЮКсЮДсЮСсЯАсЮП</b>",IK_CANCEL_DOC)
    return S_MAIN

# тФАтФА QR create тФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФА
async def qr_create(u:Update,ctx:ContextTypes.DEFAULT_TYPE):
    t=u.message.text; cid=u.message.chat_id
    def _make_qr_buf(chunk):
        for ec,nm in zip([qrcode.constants.ERROR_CORRECT_H,qrcode.constants.ERROR_CORRECT_Q,qrcode.constants.ERROR_CORRECT_M,qrcode.constants.ERROR_CORRECT_L],["H","Q","M","L"]):
            try:
                qr=qrcode.QRCode(version=None,error_correction=ec,box_size=40,border=1)
                qr.add_data(chunk); qr.make(fit=True)
                img=qr.make_image(fill_color="#000000",back_color="#FFFFFF").convert("L")
                bbox=img.getbbox()
                if bbox: img=img.crop(bbox)
                pad=20; cv=Image.new("L",(img.width+pad*2,img.height+pad*2),255); cv.paste(img,(pad,pad))
                cv=cv.convert("RGB").resize((2048,2048),Image.NEAREST)
                buf=io.BytesIO(); cv.save(buf,format="PNG",optimize=False,compress_level=1); buf.seek(0)
                return buf,nm
            except Exception: pass
        return None,None
    try:
        CHUNK=2800; raw=t.encode("utf-8")
        chunks=[raw[i:i+CHUNK].decode("utf-8","ignore") for i in range(0,len(raw),CHUNK)]
        total=len(chunks)
        msg=await u.message.reply_text(f"тП│ <b>сЮАсЯЖсЮЦсЮ╗сЮДсЮФсЮДсЯТсЮАсЮ╛сЮП {total} QR Code{'s' if total>1 else ''}...</b>",parse_mode=H)
        _save(ctx,msg)
        for idx,chunk in enumerate(chunks):
            buf,ec=_make_qr_buf(chunk)
            if buf is None: raise ValueError(f"chunk {idx+1} fail")
            fname=f"QRCode_HD{'_p'+str(idx+1) if total>1 else ''}.png"
            part_info=f" ({idx+1}/{total})" if total>1 else ""
            last=idx==total-1
            cap=f"тЬЕ <b>QR Code HD{part_info}</b>\nЁЯУР 2048├Ч2048  |  EC: {ec}\n\nЁЯУЭ <code>{chunk[:80]}{'тАж' if len(chunk)>80 else ''}</code>"
            await u.message.reply_document(document=InputFile(buf,filename=fname),caption=cap,parse_mode=H)
        msg=await u.message.reply_text("ЁЯСЗ <b>сЮЗсЯТсЮЪсЮ╛сЮЯсЮЪсЮ╛сЮЯ:</b>",reply_markup=IK_MAIN,parse_mode=H)
        _save(ctx,msg)
    except Exception as e:
        logger.error(f"qr_create: {e}")
        await _edit_or_send(ctx,cid,"тЭМ <b>сЮШсЮ╢сЮУсЮФсЮЙсЯТсЮасЮ╢! сЮЦсЯТсЮЩсЮ╢сЮЩсЮ╢сЮШсЮШсЯТсЮКсЮДсЮСсЯАсЮП</b>",IK_CANCEL_QR)
    return S_MAIN

# тФАтФА QR scan тФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФА
async def qr_scan(u:Update,ctx:ContextTypes.DEFAULT_TYPE):
    p=u.message.photo[-1] if u.message.photo else None
    dc=u.message.document if u.message.document else None
    cid=u.message.chat_id
    if not p and not dc:
        await _edit_or_send(ctx,cid,"тЪая╕П Upload <b>сЮЪсЮ╝сЮФсЮЧсЮ╢сЮЦ QR</b>!",IK_CANCEL_QR); return S_QR_SCAN
    try:
        raw=bytes(await (await ctx.bot.get_file(p.file_id if p else dc.file_id)).download_as_bytearray())
        img=Image.open(io.BytesIO(raw)).convert("RGB"); codes=pyzbar.decode(img)
        if not codes:
            await _edit_or_send(ctx,cid,"тЭМ <b>сЮЪсЮАсЮШсЮ╖сЮУсЮГсЮ╛сЮЙ QR Code!</b>\nсЮЯсЮ╝сЮШ Upload сЮЪсЮ╝сЮФсЮЧсЮ╢сЮЦсЮЕсЯТсЮФсЮ╢сЮЯсЯЛсЮЗсЮ╢сЮД",IK_CANCEL_QR); return S_QR_SCAN
        lines="\n\n".join(f"ЁЯУМ <b>сЮЫсЮСсЯТсЮТсЮХсЮЫсЮСсЮ╕ {i+1}:</b>\n<code>{c.data.decode('utf-8','replace')}</code>" for i,c in enumerate(codes))
        await u.message.reply_text(f"тЬЕ <b>Scan QR сЮЗсЯДсЮВсЮЗсЯРсЮЩ!</b> ({len(codes)} QR)\nтФБтФБтФБтФБтФБтФБтФБтФБтФБ\n{lines}",parse_mode=H)
        msg=await u.message.reply_text("ЁЯСЗ <b>сЮЗсЯТсЮЪсЮ╛сЮЯсЮЪсЮ╛сЮЯ:</b>",reply_markup=IK_MAIN,parse_mode=H)
        _save(ctx,msg)
    except Exception as e:
        logger.error(f"qr_scan: {e}")
        await _edit_or_send(ctx,cid,"тЭМ <b>сЮШсЮ╢сЮУсЮФсЮЙсЯТсЮасЮ╢! сЮЦсЯТсЮЩсЮ╢сЮЩсЮ╢сЮШсЮШсЯТсЮКсЮДсЮСсЯАсЮП</b>",IK_CANCEL_QR)
    return S_MAIN

# тФАтФА fallback тФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФА
async def fallback(u:Update,ctx:ContextTypes.DEFAULT_TYPE):
    ctx.user_data.clear()
    msg=await u.message.reply_text("ЁЯСЗ <b>сЮЗсЯТсЮЪсЮ╛сЮЯсЮЪсЮ╛сЮЯ:</b>",reply_markup=IK_MAIN,parse_mode=H)
    _save(ctx,msg); return S_MAIN

def main():
    app=Application.builder().token(BOT_TOKEN).connect_timeout(10).read_timeout(30).write_timeout(30).pool_timeout(10).build()
    TXT=filters.TEXT&~filters.COMMAND
    IMG=filters.PHOTO|filters.Document.IMAGE
    PDF_F=filters.Document.MimeType("application/pdf")|filters.Document.FileExtension("pdf")
    CBQ=CallbackQueryHandler(cb)
    app.add_handler(ConversationHandler(
        entry_points=[CommandHandler("start",cmd_start),MessageHandler(filters.ALL,fallback)],
        states={
            S_MAIN:      [CBQ],
            S_DOC:       [CBQ],
            S_STYLE:     [MessageHandler(TXT,style_handler),    CBQ],
            S_PDF:       [MessageHandler(IMG,pdf_photo),        CBQ],
            S_PDF2IMG:   [MessageHandler(PDF_F,pdf2img),        CBQ],
            S_QR:        [CBQ],
            S_QR_CREATE: [MessageHandler(TXT,qr_create),       CBQ],
            S_QR_SCAN:   [MessageHandler(IMG,qr_scan),         CBQ],
        },
        fallbacks=[CommandHandler("start",cmd_start),MessageHandler(filters.ALL,fallback)],
        per_message=False,allow_reentry=False,
    ))
    logger.info("ЁЯдЦ Bot сЮАсЯЖсЮЦсЮ╗сЮД Start..."); app.run_polling(allowed_updates=Update.ALL_TYPES,poll_interval=1.0,drop_pending_updates=True)
if __name__=="__main__": main()
